export function Badge({ label }: { label: string }) {
  return (
    <span className="px-2 py-1 rounded text-sm bg-accent">
      {label}
    </span>
  );
}

interface CardProps {
  titre: string;
  description: string;
  niveau: "débutant" | "intermédiaire" | "avancé";
}

export function Card({ titre, description, niveau }: CardProps) {
  return <div>{titre}</div>;
}

